import sqlite3
import os
import logging
from pathlib import Path
from contextlib import contextmanager
from enum import IntEnum
from typing import Optional

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class AccessLevel(IntEnum):
    NONE = 0
    READ = 1
    WRITE = 2
    ADMIN = 3


class PermissionDeniedError(Exception):
    pass


class FileNotFoundInSystemError(Exception):
    pass


class FileAccessControlSystem:
    # Allowed base directory for all managed documents
    ALLOWED_BASE_DIR = None

    def __init__(self, db_path: str, document_root: str):
        self.db_path = db_path
        self.document_root = os.path.realpath(document_root)
        FileAccessControlSystem.ALLOWED_BASE_DIR = self.document_root

        if not os.path.isdir(self.document_root):
            os.makedirs(self.document_root, exist_ok=True)

        self._initialize_database()

    @contextmanager
    def _get_db_connection(self):
        conn = sqlite3.connect(self.db_path)
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA foreign_keys=ON")
        try:
            yield conn
            conn.commit()
        except Exception:
            conn.rollback()
            raise
        finally:
            conn.close()

    def _initialize_database(self):
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute("""
                CREATE TABLE IF NOT EXISTS users (
                    user_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    username TEXT UNIQUE NOT NULL
                )
            """)
            cursor.execute("""
                CREATE TABLE IF NOT EXISTS documents (
                    doc_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    doc_name TEXT UNIQUE NOT NULL,
                    relative_path TEXT NOT NULL
                )
            """)
            cursor.execute("""
                CREATE TABLE IF NOT EXISTS permissions (
                    permission_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER NOT NULL,
                    doc_id INTEGER NOT NULL,
                    access_level INTEGER NOT NULL DEFAULT 0,
                    FOREIGN KEY (user_id) REFERENCES users(user_id) ON DELETE CASCADE,
                    FOREIGN KEY (doc_id) REFERENCES documents(doc_id) ON DELETE CASCADE,
                    UNIQUE(user_id, doc_id)
                )
            """)
            cursor.execute("""
                CREATE INDEX IF NOT EXISTS idx_permissions_user_doc
                ON permissions(user_id, doc_id)
            """)

    def _validate_and_resolve_path(self, relative_path: str) -> str:
        """Resolve a relative path within the document root, preventing path traversal."""
        # Normalize and resolve the path
        candidate = os.path.realpath(os.path.join(self.document_root, relative_path))

        # Ensure the resolved path is within the document root
        if not candidate.startswith(self.document_root + os.sep) and candidate != self.document_root:
            logger.warning(
                "Path traversal attempt detected: %s resolved to %s",
                relative_path, candidate
            )
            raise PermissionDeniedError("Invalid file path: path traversal detected")

        return candidate

    def add_user(self, username: str) -> int:
        """Add a user and return their user_id."""
        if not username or not isinstance(username, str):
            raise ValueError("Username must be a non-empty string")

        username = username.strip()
        if not username.isalnum() and not all(c.isalnum() or c in ('_', '-', '.') for c in username):
            raise ValueError("Username contains invalid characters")

        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute("INSERT INTO users (username) VALUES (?)", (username,))
            return cursor.lastrowid

    def register_document(self, doc_name: str, relative_path: str) -> int:
        """Register a document in the system. The relative_path is relative to document_root."""
        if not doc_name or not isinstance(doc_name, str):
            raise ValueError("Document name must be a non-empty string")

        # Validate the path doesn't escape the document root
        resolved = self._validate_and_resolve_path(relative_path)

        if not os.path.isfile(resolved):
            raise FileNotFoundInSystemError(f"File does not exist at resolved path")

        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute(
                "INSERT INTO documents (doc_name, relative_path) VALUES (?, ?)",
                (doc_name.strip(), relative_path)
            )
            return cursor.lastrowid

    def grant_permission(self, username: str, doc_name: str, access_level: AccessLevel):
        """Grant a specific access level to a user for a document."""
        if not isinstance(access_level, AccessLevel):
            raise ValueError("access_level must be an AccessLevel enum value")

        with self._get_db_connection() as conn:
            cursor = conn.cursor()

            cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
            user_row = cursor.fetchone()
            if not user_row:
                raise ValueError(f"User not found: {username}")

            cursor.execute("SELECT doc_id FROM documents WHERE doc_name = ?", (doc_name,))
            doc_row = cursor.fetchone()
            if not doc_row:
                raise ValueError(f"Document not found: {doc_name}")

            cursor.execute("""
                INSERT INTO permissions (user_id, doc_id, access_level)
                VALUES (?, ?, ?)
                ON CONFLICT(user_id, doc_id) DO UPDATE SET access_level = excluded.access_level
            """, (user_row[0], doc_row[0], int(access_level)))

        logger.info(
            "Permission updated: user=%s, doc=%s, level=%s",
            username, doc_name, access_level.name
        )

    def revoke_permission(self, username: str, doc_name: str):
        """Revoke all permissions for a user on a document."""
        with self._get_db_connection() as conn:
            cursor = conn.cursor()

            cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
            user_row = cursor.fetchone()
            if not user_row:
                raise ValueError(f"User not found: {username}")

            cursor.execute("SELECT doc_id FROM documents WHERE doc_name = ?", (doc_name,))
            doc_row = cursor.fetchone()
            if not doc_row:
                raise ValueError(f"Document not found: {doc_name}")

            cursor.execute(
                "DELETE FROM permissions WHERE user_id = ? AND doc_id = ?",
                (user_row[0], doc_row[0])
            )

        logger.info("Permission revoked: user=%s, doc=%s", username, doc_name)

    def _check_permission(self, username: str, doc_name: str, required_level: AccessLevel) -> bool:
        """
        Check if a user has at least the required access level for a document.
        Always queries the database to get the current permission state.
        """
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute("""
                SELECT p.access_level
                FROM permissions p
                JOIN users u ON p.user_id = u.user_id
                JOIN documents d ON p.doc_id = d.doc_id
                WHERE u.username = ? AND d.doc_name = ?
            """, (username, doc_name))

            row = cursor.fetchone()
            if row is None:
                return False

            return row[0] >= int(required_level)

    def _get_document_path(self, doc_name: str) -> str:
        """Retrieve and validate the file path for a registered document."""
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute(
                "SELECT relative_path FROM documents WHERE doc_name = ?",
                (doc_name,)
            )
            row = cursor.fetchone()
            if not row:
                raise FileNotFoundInSystemError(f"Document not registered: {doc_name}")

            relative_path = row[0]

        # Re-validate path at access time (defense in depth)
        resolved = self._validate_and_resolve_path(relative_path)

        if not os.path.isfile(resolved):
            raise FileNotFoundInSystemError("Document file no longer exists on disk")

        return resolved

    def read_file(self, username: str, doc_name: str, max_size: int = 10 * 1024 * 1024) -> str:
        """
        Read a file's contents if the user has at least READ permission.

        Args:
            username: The username requesting access.
            doc_name: The registered document name.
            max_size: Maximum file size in bytes to read (default 10MB).

        Returns:
            The file contents as a string.

        Raises:
            PermissionDeniedError: If the user lacks read permission.
            FileNotFoundInSystemError: If the document is not registered or file is missing.
            ValueError: If the file exceeds max_size.
        """
        if not username or not isinstance(username, str):
            raise ValueError("Username must be a non-empty string")
        if not doc_name or not isinstance(doc_name, str):
            raise ValueError("Document name must be a non-empty string")

        # Always check permission fresh from the database
        if not self._check_permission(username, doc_name, AccessLevel.READ):
            logger.warning(
                "Permission denied: user=%s attempted to read doc=%s",
                username, doc_name
            )
            raise PermissionDeniedError(
                f"User '{username}' does not have read access to '{doc_name}'"
            )

        file_path = self._get_document_path(doc_name)

        # Check file size before reading
        file_size = os.path.getsize(file_path)
        if file_size > max_size:
            raise ValueError(
                f"File size ({file_size} bytes) exceeds maximum allowed size ({max_size} bytes)"
            )

        try:
            with open(file_path, "r", encoding="utf-8") as f:
                contents = f.read(max_size)
        except UnicodeDecodeError:
            raise ValueError("File contains invalid UTF-8 content")
        except OSError as e:
            logger.error("Error reading file for doc=%s: %s", doc_name, e)
            raise

        logger.info("File read successfully: user=%s, doc=%s", username, doc_name)
        return contents

    def get_user_permissions(self, username: str) -> dict:
        """Get all document permissions for a user."""
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute("""
                SELECT d.doc_name, p.access_level
                FROM permissions p
                JOIN users u ON p.user_id = u.user_id
                JOIN documents d ON p.doc_id = d.doc_id
                WHERE u.username = ?
            """, (username,))

            return {
                row[0]: AccessLevel(row[1]).name
                for row in cursor.fetchall()
            }


